from itertools import combinations

class Solution:
    def minLength(self, s, numOps):
        n = len(s)
        best = n
        for r in range(0, numOps + 1):
            for combo in combinations(range(n), r):
                t = list(s)
                for i in combo:
                    t[i] = '1' if t[i] == '0' else '0'
                mx = 1
                cur = 1
                for k in range(1, n):
                    if t[k] == t[k - 1]:
                        cur += 1
                        if cur > mx:
                            mx = cur
                    else:
                        cur = 1
                if mx < best:
                    best = mx
        return best

