class Solution:
    def minLength(self, s: str, numOps: int) -> int:
        n = len(s)
        runs = []
        i = 0
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            runs.append(j - i)
            i = j

        def feasible(L):
            total = 0
            for r in runs:
                total += r // (L + 1)
                if total > numOps:
                    return False
            return True

        lo, hi = 1, n
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

