var minLength = function(s, numOps) {
    const n = s.length;
    const runs = [];
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && s[j] === s[i]) j++;
        runs.push(j - i);
        i = j;
    }
    const feasible = (L) => {
        let total = 0;
        for (const r of runs) {
            total += Math.floor(r / (L + 1));
            if (total > numOps) return false;
        }
        return true;
    };
    let lo = 1, hi = n;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (feasible(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
